import{_ as n,c as t,o as i,a1 as r}from"./chunks/framework.DILC4Csi.js";const k=JSON.parse('{"title":"Skill-Entwicklung: Benutzerdefinierte Skills | Agent Skills","description":"Lernen Sie benutzerdefinierte Skills für Claude zu entwickeln. Erfahren Sie, wie Sie Verzeichnisstrukturen erstellen, SKILL.md definieren, Skripte schreiben und Skills als Zip veröffentlichen.","frontmatter":{"title":"Skill-Entwicklung: Benutzerdefinierte Skills | Agent Skills","sidebarTitle":"Skill-Entwicklung","subtitle":"Skill-Entwicklung","description":"Lernen Sie benutzerdefinierte Skills für Claude zu entwickeln. Erfahren Sie, wie Sie Verzeichnisstrukturen erstellen, SKILL.md definieren, Skripte schreiben und Skills als Zip veröffentlichen.","tags":["Skill-Entwicklung","Claude","KI-Hilfsprogrammierung","benutzerdefinierte Erweiterungen"],"prerequisite":["start-getting-started","start-installation"]},"headers":[],"relativePath":"de/vercel-labs/agent-skills/advanced/skill-development/index.md","filePath":"de/vercel-labs/agent-skills/advanced/skill-development/index.md"}'),s={name:"de/vercel-labs/agent-skills/advanced/skill-development/index.md"};function a(l,e,d,o,c,u){return i(),t("div",null,[...e[0]||(e[0]=[r(`<h1 id="entwicklung-benutzerdefinierter-skills" tabindex="-1">Entwicklung benutzerdefinierter Skills <a class="header-anchor" href="#entwicklung-benutzerdefinierter-skills" aria-label="Permalink to &quot;Entwicklung benutzerdefinierter Skills&quot;">​</a></h1><h2 id="was-sie-nach-diesem-kurs-konnen" tabindex="-1">Was Sie nach diesem Kurs können <a class="header-anchor" href="#was-sie-nach-diesem-kurs-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Kurs können&quot;">​</a></h2><p>Lernen Sie nach Abschluss dieser Lektion:</p><ul><li>✅ Spezifikationsgerechte Skill-Verzeichnisstruktur erstellen</li><li>✅ Vollständige <code>SKILL.md</code>-Definitionsdatei schreiben (inklusive Front Matter, How It Works, Usage usw.)</li><li>✅ Spezifikationskonforme Bash-Skripte schreiben (Fehlerbehandlung, Ausgabeformat, Bereinigungsmechanismus)</li><li>✅ Skills als Zip-Datei packen und veröffentlichen</li><li>✅ Kontexteffizienz optimieren, damit Claude Skills präziser aktiviert</li></ul><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p><strong>Arbeitsweise von Agent Skills</strong>:</p><p>Claude lädt beim Start nur den <strong>Namen und die Beschreibung</strong> des Skills. Wenn relevante Keywords erkannt werden, wird der vollständige Inhalt von <code>SKILL.md</code> gelesen. Dieser <strong>On-Demand-Lademechanismus</strong> minimiert den Token-Verbrauch.</p><p><strong>Drei Kernkomponenten der Skill-Entwicklung</strong>:</p><ol><li><strong>Verzeichnisstruktur</strong>: Ordner-Layout, das den Benennungskonventionen entspricht</li><li><strong>SKILL.md</strong>: Skill-Definitionsdatei, die Claude mitteilt, wann der Skill aktiviert werden soll und wie er zu verwenden ist</li><li><strong>Skripte</strong>: Tatsächlich auszuführender Bash-Code, der spezifische Aufgaben ausführt</li></ol><h2 id="schritt-fur-schritt-anleitung" tabindex="-1">Schritt-für-Schritt-Anleitung <a class="header-anchor" href="#schritt-fur-schritt-anleitung" aria-label="Permalink to &quot;Schritt-für-Schritt-Anleitung&quot;">​</a></h2><h3 id="schritt-1-verzeichnisstruktur-erstellen" tabindex="-1">Schritt 1: Verzeichnisstruktur erstellen <a class="header-anchor" href="#schritt-1-verzeichnisstruktur-erstellen" aria-label="Permalink to &quot;Schritt 1: Verzeichnisstruktur erstellen&quot;">​</a></h3><p>Korrekte Verzeichnisstruktur ist Voraussetzung dafür, dass Claude den Skill erkennen kann.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-custom-skill</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-custom-skill</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts</span></span></code></pre></div><h3 id="schritt-2-skill-md-schreiben" tabindex="-1">Schritt 2: SKILL.md schreiben <a class="header-anchor" href="#schritt-2-skill-md-schreiben" aria-label="Permalink to &quot;Schritt 2: SKILL.md schreiben&quot;">​</a></h3><p><code>SKILL.md</code> ist der Kern des Skills und definiert die Auslösbedingungen, die Verwendungsmethode und das Ausgabeformat.</p><h3 id="schritt-3-bash-skripte-schreiben" tabindex="-1">Schritt 3: Bash-Skripte schreiben <a class="header-anchor" href="#schritt-3-bash-skripte-schreiben" aria-label="Permalink to &quot;Schritt 3: Bash-Skripte schreiben&quot;">​</a></h3><p>Skripte sind der Teil, der die tatsächliche Ausführung übernimmt und den Eingabe-Ausgabe-Spezifikationen von Claude entsprechen muss.</p><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p><strong>Kernpunkte</strong>:</p><ol><li><strong>Verzeichnisstruktur</strong>: Verwendung von kebab-case, Enthalt von <code>SKILL.md</code> und <code>scripts/</code>-Verzeichnis</li><li><strong>SKILL.md-Format</strong>: Front Matter + How It Works + Usage + Output + Present Results to User + Troubleshooting</li><li><strong>Skript-Spezifikation</strong>: <code>#!/bin/bash</code>, <code>set -e</code>, stderr für Status, stdout für JSON, cleanup trap</li><li><strong>Kontexteffizienz</strong>: <code>SKILL.md</code> &lt; 500 Zeilen, progressive Disclosure, priorisierte Skripte</li><li><strong>Packen und Veröffentlichen</strong>: Verwenden Sie <code>zip -r</code> zum Packen als <code>{skill-name}.zip</code></li></ol><p><strong>Best-Practices-Mantra</strong>:</p><blockquote><p>Beschreibungen sollen spezifisch sein, Auslösungen klar Status über stderr, JSON über stdout Remember trap hinzufügen, temporäre Dateien bereinigen Dateien nicht zu lang, Skripte nutzen den Platz</p></blockquote><hr><h2 id="anhang-quellcodereferenz" tabindex="-1">Anhang: Quellcodereferenz <a class="header-anchor" href="#anhang-quellcodereferenz" aria-label="Permalink to &quot;Anhang: Quellcodereferenz&quot;">​</a></h2><details><summary><strong>Klicken zum Anzeigen der Quellcodepositionen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-25</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Verzeichnisstrukturdefinition</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L11-L20" target="_blank" rel="noreferrer"><code>AGENTS.md:11-20</code></a></td><td>11-20</td></tr><tr><td>Benennungskonvention</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L22-L27" target="_blank" rel="noreferrer"><code>AGENTS.md:22-27</code></a></td><td>22-27</td></tr><tr><td>SKILL.md Format</td><td><a href="https://github.com/vercel-labs/agent-skills/blob/main/AGENTS.md#L29-L68" target="_blank" rel="noreferrer"><code>AGENTS.md:29-68</code></a></td><td>29-68</td></tr></tbody></table><p><strong>Wichtige Konstanten</strong>:</p><ul><li><code>SKILL.md</code>-Dateiname: Muss GROSSBUCHSTABEN sein, muss exakt übereinstimmen</li><li><code>/mnt/skills/user/{skill-name}/scripts/{script}.sh</code>: Skript-Pfadformat</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li>Skript-Bereinigungsfunktion <code>cleanup()</code>: Zum Löschen temporärer Dateien</li><li>Framework-Erkennungsfunktion <code>detect_framework()</code>: Erkennt Framework-Typ aus package.json</li></ul></details>`,25)])])}const p=n(s,[["render",a]]);export{k as __pageData,p as default};
